final:
module RefModule (  
    input clk,  
    input reset,  
    input [7:0] seed,  
    output reg [7:0] lfsr_out  
);  
    wire feedback;  
    assign feedback = lfsr_out[7] ^ lfsr_out[5] ^ lfsr_out[4] ^ lfsr_out[3];  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin  
        if (reset) begin  
            lfsr_out <= seed;  
        end else begin  
            lfsr_out <= {lfsr_out[6:0], feedback};  
        end  
    end  
endmodule
